212. async function handler(req, res) {
213.   const url = new URL(req.url, `http://${req.headers.host || "localhost"}`);
214. 
215.   if (req.method === "GET" && (url.pathname === "/" || url.pathname === "/index.html")) {
216.     return sendFile(res, path.join(PUBLIC_DIR, "index.html"), "text/html; charset=utf-8");
217.   }
218.   if (req.method === "GET" && url.pathname === "/styles.css") {
219.     return sendFile(res, path.join(PUBLIC_DIR, "styles.css"), "text/css; charset=utf-8");
220.   }
221.   if (req.method === "GET" && url.pathname === "/app.js") {
222.     return sendFile(res, path.join(PUBLIC_DIR, "app.js"), "text/javascript; charset=utf-8");
223.   }
224. 
225.   if (req.method === "GET" && url.pathname === "/api/config") {
226.     return sendJson(res, 200, { baseDir: BASE_DIR, copilotBin: COPILOT_BIN });
227.   }
228. 
229.   if (req.method === "GET" && url.pathname === "/api/tree") {
230.     const unsafePath = url.searchParams.get("path") || BASE_DIR;
231.     const safePath = toSafeAbsolute(unsafePath);
232.     if (!safePath) return sendJson(res, 400, { error: "Path is outside allowed root." });
233.     try {
234.       const dirs = await listDirectories(safePath);
235.       const parentPath = safePath === BASE_DIR ? null : path.dirname(safePath);
236.       return sendJson(res, 200, {
237.         currentPath: safePath,
238.         relativePath: path.relative(BASE_DIR, safePath) || ".",
239.         parentPath,
240.         children: dirs,
241.       });
242.     } catch (error) {
243.       return sendJson(res, 500, { error: `Unable to read directory: ${String(error.message || error)}` });
244.     }
245.   }
246. 
247.   if (req.method === "GET" && url.pathname === "/api/sessions") {
248.     return sendJson(
249.       res,
250.       200,
251.       { sessions: Array.from(sessions.values()).map(sessionToDto).sort((a, b) => b.createdAt.localeCompare(a.createdAt)) }
252.     );
253.   }
254. 
255.   if (req.method === "POST" && url.pathname === "/api/sessions") {
256.     try {
257.       const body = await readBody(req);
258.       const safePath = toSafeAbsolute(body.path);
259.       if (!safePath) return sendJson(res, 400, { error: "Directory is outside allowed root." });
260. 
261.       const stat = await fsp.stat(safePath);
262.       if (!stat.isDirectory()) return sendJson(res, 400, { error: "Target path is not a directory." });
263.       const hasGit = await isGitRepository(safePath);
264.       if (!hasGit) {
265.         return sendJson(res, 400, { error: "Target must be a git repository. Clone a repo first, then deploy." });
266.       }
267. 
268.       const session = await launchSession(safePath, Boolean(body.yolo));
269.       return sendJson(res, 201, { session: sessionToDto(session) });
270.     } catch (error) {
271.       return sendJson(res, 500, { error: `Unable to launch session: ${String(error.message || error)}` });
272.     }
273.   }
274. 
275.   if (req.method === "POST" && url.pathname === "/api/folders") {
276.     try {
277.       const body = await readBody(req);
278.       const parent = toSafeAbsolute(body.parentPath);
279.       if (!parent) return sendJson(res, 400, { error: "Parent path is outside allowed root." });
280.       const stat = await fsp.stat(parent);
281.       if (!stat.isDirectory()) return sendJson(res, 400, { error: "Parent path is not a directory." });
282. 
283.       const nameError = validateFolderName(body.name);
284.       if (nameError) return sendJson(res, 400, { error: nameError });
285. 
286.       const createdPath = path.join(parent, body.name.trim());
287.       const safeCreatedPath = toSafeAbsolute(createdPath);
288.       if (!safeCreatedPath) return sendJson(res, 400, { error: "Resulting path is outside allowed root." });
289. 
290.       await fsp.mkdir(safeCreatedPath);
291.       return sendJson(res, 201, {
292.         folder: {
293.           name: path.basename(safeCreatedPath),
294.           path: safeCreatedPath,
295.           relativePath: path.relative(BASE_DIR, safeCreatedPath) || ".",
296.         },
297.       });
298.     } catch (error) {
299.       if (error && error.code === "EEXIST") return sendJson(res, 409, { error: "Folder already exists." });
300.       return sendJson(res, 500, { error: `Unable to create folder: ${String(error.message || error)}` });
301.     }
302.   }
303. 
304.   if (req.method === "POST" && url.pathname === "/api/clone") {
305.     try {
306.       const body = await readBody(req);
307.       const parent = toSafeAbsolute(body.parentPath);
308.       if (!parent) return sendJson(res, 400, { error: "Parent path is outside allowed root." });
309.       const parentStat = await fsp.stat(parent);
310.       if (!parentStat.isDirectory()) return sendJson(res, 400, { error: "Parent path is not a directory." });
311.       if (typeof body.repoUrl !== "string" || !body.repoUrl.trim()) {
312.         return sendJson(res, 400, { error: "Repository URL is required." });
313.       }
314. 
315.       const targetName = typeof body.folderName === "string" && body.folderName.trim()
316.         ? body.folderName.trim()
317.         : deriveRepoFolderName(body.repoUrl);
318.       const nameError = validateFolderName(targetName);
319.       if (nameError) return sendJson(res, 400, { error: nameError });
320. 
321.       const targetPath = toSafeAbsolute(path.join(parent, targetName));
322.       if (!targetPath) return sendJson(res, 400, { error: "Clone path is outside allowed root." });
323.       try {
324.         await fsp.access(targetPath);
325.         return sendJson(res, 409, { error: "Target folder already exists." });
326.       } catch {
327.         // Path is free.
328.       }
329. 
330.       await runCommand("git", ["clone", body.repoUrl.trim(), targetPath], parent);
331.       return sendJson(res, 201, {
332.         folder: {
333.           name: path.basename(targetPath),
334.           path: targetPath,
335.           relativePath: path.relative(BASE_DIR, targetPath) || ".",
336.         },
337.       });
338.     } catch (error) {
339.       return sendJson(res, 500, { error: `Unable to clone repository: ${String(error.message || error)}` });
340.     }
341.   }
342. 
343.   if (req.method === "POST" && url.pathname === "/api/init-repo") {
344.     try {
345.       const body = await readBody(req);
346.       const safePath = toSafeAbsolute(body.path);
347.       if (!safePath) return sendJson(res, 400, { error: "Path is outside allowed root." });
348.       const stat = await fsp.stat(safePath);
349.       if (!stat.isDirectory()) return sendJson(res, 400, { error: "Target path is not a directory." });
350. 
351.       const hasGit = await isGitRepository(safePath);
352.       if (hasGit) return sendJson(res, 200, { ok: true, message: "Already a git repository." });
353. 
354.       await runCommand("git", ["init"], safePath);
355.       return sendJson(res, 201, { ok: true });
356.     } catch (error) {
357.       return sendJson(res, 500, { error: `Unable to initialize repository: ${String(error.message || error)}` });
358.     }
359.   }
360. 
361.   if (req.method === "POST" && url.pathname.startsWith("/api/sessions/") && url.pathname.endsWith("/stop")) {
362.     const id = url.pathname.slice("/api/sessions/".length, -"/stop".length);
363.     const session = sessions.get(id);
364.     if (!session) return sendJson(res, 404, { error: "Session not found." });
365.     if (session.status !== "running") return sendJson(res, 400, { error: "Session is not running." });
366. 
367.     try {
368.       process.kill(session.pid, "SIGTERM");
369.       session.status = "stopping";
370.       return sendJson(res, 200, { session: sessionToDto(session) });
371.     } catch (error) {
372.       return sendJson(res, 500, { error: `Unable to stop session: ${String(error.message || error)}` });
373.     }
374.   }
375. 
376.   if (req.method === "GET" && url.pathname.startsWith("/api/sessions/") && url.pathname.endsWith("/log")) {
377.     const id = url.pathname.slice("/api/sessions/".length, -"/log".length);
378.     const session = sessions.get(id);
379.     if (!session) return sendJson(res, 404, { error: "Session not found." });
380.     const tail = Number(url.searchParams.get("tail") || 300);
381.     const safeTail = Number.isFinite(tail) ? Math.max(20, Math.min(2000, tail)) : 300;
382.     const output = await readTailLines(session.logFile, safeTail);
383.     return sendJson(res, 200, { output });
384.   }
385. 
386.   if (req.method === "DELETE" && url.pathname.startsWith("/api/sessions/")) {
387.     const id = url.pathname.slice("/api/sessions/".length);
388.     const session = sessions.get(id);
389.     if (!session) return sendJson(res, 404, { error: "Session not found." });
390.     if (session.status === "running" || session.status === "stopping") {
391.       return sendJson(res, 400, { error: "Stop the session before removing it." });
392.     }
393.     sessions.delete(id);
394.     return sendJson(res, 200, { ok: true });
395.   }
396. 
397.   res.writeHead(404, { "Content-Type": "application/json; charset=utf-8" });
398.   res.end(JSON.stringify({ error: "Not found." }));
399. }
400. 
401. async function start() {
402.   await ensureLogDir();
403.   const server = http.createServer((req, res) => {
404.     handler(req, res).catch((error) => {
405.       sendJson(res, 500, { error: `Unexpected error: ${String(error.message || error)}` });
406.     });
407.   });
408.   server.listen(PORT, () => {
409.     process.stdout.write(`Copilot Spawner running on http://localhost:${PORT}\n`);
410.     process.stdout.write(`Allowed root: ${BASE_DIR}\n`);
411.     process.stdout.write(`Copilot binary: ${COPILOT_BIN}\n`);
412.   });
413. }
414. 
415. start().catch((err) => {
416.   process.stderr.write(`${String(err)}\n`);
417.   process.exit(1);
418. });
