1. const state = {
2.   baseDir: "",
3.   currentPath: "",
4.   parentPath: null,
5.   openLogSessionId: null,
6.   openLogContent: "",
7. };
8. 
9. const els = {
10.   dirList: document.getElementById("dir-list"),
11.   sessionList: document.getElementById("session-list"),
12.   pathLabel: document.getElementById("path-label"),
13.   upBtn: document.getElementById("up-btn"),
14.   deployHereBtn: document.getElementById("deploy-here-btn"),
15.   deployHereYolo: document.getElementById("deploy-here-yolo"),
16.   initRepoBtn: document.getElementById("init-repo-btn"),
17.   createFolderBtn: document.getElementById("create-folder-btn"),
18.   newFolderName: document.getElementById("new-folder-name"),
19.   cloneRepoUrl: document.getElementById("clone-repo-url"),
20.   cloneFolderName: document.getElementById("clone-folder-name"),
21.   cloneRepoBtn: document.getElementById("clone-repo-btn"),
22.   flash: document.getElementById("flash"),
23.   refreshBtn: document.getElementById("refresh-btn"),
24. };
25. 
26. async function request(url, options = {}) {
27.   const res = await fetch(url, options);
28.   const data = await res.json();
29.   if (!res.ok) throw new Error(data.error || "Request failed.");
30.   return data;
31. }
32. 
33. function escapeHtml(text) {
34.   return String(text)
35.     .replaceAll("&", "&amp;")
36.     .replaceAll("<", "&lt;")
37.     .replaceAll(">", "&gt;")
38.     .replaceAll('"', "&quot;")
39.     .replaceAll("'", "&#39;");
40. }
41. 
42. function setFlash(message, type = "ok") {
43.   els.flash.classList.remove("ok", "error");
44.   els.flash.classList.add(type);
45.   els.flash.textContent = message;
46. }
47. 
48. async function loadConfig() {
49.   const data = await request("/api/config");
50.   state.baseDir = data.baseDir;
51. }
52. 
53. async function loadDirectory(path) {
54.   const url = new URL("/api/tree", window.location.origin);
55.   if (path) url.searchParams.set("path", path);
56.   const data = await request(url.toString());
57.   state.currentPath = data.currentPath;
58.   state.parentPath = data.parentPath;
59.   els.pathLabel.textContent = data.currentPath;
60.   els.upBtn.disabled = !data.parentPath;
61. 
62.   els.dirList.innerHTML = data.children.length
63.     ? data.children.map((dir) => {
64.         const escapedPath = escapeHtml(dir.path);
65.         const escapedName = escapeHtml(dir.name);
66.         const escapedRel = escapeHtml(dir.relativePath);
67.         return `
68.           <div class="item">
69.             <div>
70.               <div class="name">${escapedName}</div>
71.               <div class="meta">${escapedRel}</div>
72.             </div>
73.             <div class="right">
74.               <button data-open="${escapedPath}">Open</button>
75.               <div class="inline-actions">
76.                 <button data-launch="${escapedPath}">Deploy</button>
77.                 <label class="toggle">
78.                   <input type="checkbox" data-item-yolo>
79.                   <span>--yolo</span>
80.                 </label>
81.               </div>
82.             </div>
83.           </div>
84.         `;
85.       }).join("")
86.     : `<div class="item"><div><div class="name">This folder is empty</div><div class="meta">Use Deploy Here, Create Folder, Clone Repo, or Init Git Here.</div></div></div>`;
87. }
88. 
89. function renderSessionLog(sessionId) {
90.   if (state.openLogSessionId !== sessionId) return "";
91.   return `<pre class="session-log">${escapeHtml(state.openLogContent || "(no output yet)")}</pre>`;
92. }
93. 
94. async function loadSessions() {
95.   const data = await request("/api/sessions");
96.   els.sessionList.innerHTML = data.sessions.length
97.     ? data.sessions.map((session) => {
98.         const escapedId = escapeHtml(session.id);
99.         const escapedDir = escapeHtml(session.directory);
100.         const escapedArgs = escapeHtml(session.args.join(" "));
101.         const outputButton = state.openLogSessionId === session.id ? "Hide Output" : "Show Output";
102.         return `
103.           <div class="item">
104.             <div style="flex:1;">
105.               <div class="name">${escapedDir}</div>
106.               <div class="meta">PID ${session.pid} · ${session.command} ${escapedArgs}</div>
107.               <div class="badge status-${session.status}">${escapeHtml(session.status)}</div>
108.               ${renderSessionLog(session.id)}
109.             </div>
110.             <div class="right">
111.               <button data-output="${escapedId}">${outputButton}</button>
112.               <button data-stop="${escapedId}">Stop</button>
113.               <button data-remove="${escapedId}">Remove</button>
114.             </div>
115.           </div>
116.         `;
117.       }).join("")
118.     : `<div class="item"><div class="meta">No sessions yet.</div></div>`;
119. }
120. 
121. async function createSession(dirPath, yolo) {
122.   await request("/api/sessions", {
123.     method: "POST",
124.     headers: { "Content-Type": "application/json" },
125.     body: JSON.stringify({ path: dirPath, yolo: Boolean(yolo) }),
126.   });
127.   await loadSessions();
128.   setFlash(`Session launched in ${dirPath}`, "ok");
129. }
