 function get(id) {
 	return document.getElementById(id)
 }

 function getClasses(name) {
 	return document.getElementsByClassName(name)
 }

 function set(id, value) {
 	return get(id).innerText = value
 }

 function s(number) {
 	if (number !== 1) return "s"
 	return ""
 }

 Array.prototype.max = function() {
 	let arr = this
 	arr = arr.filter(element => {
 		return element !== null && element !== undefined
 	})
 	let n = Math.max.apply(null, arr)
 	if (Math.abs(n) == Infinity) n = null
 	return n
 }

 Array.prototype.min = function() {
 	let arr = this
 	arr = arr.filter(element => {
 		return element !== null && element !== undefined
 	})
 	let n = Math.min.apply(null, arr)
 	if (Math.abs(n) == Infinity) n = null
 	return n
 }

 Array.prototype.addNode = function() {
 	let value = arguments[0]
 	let push = arguments[1]
 	push = (Array.isArray(push)) ? push : [push]
 	if (!push.includes(null) && !push.includes(false)) this.push(value)
 }

 Array.prototype.append = function() {
 	let value = arguments[0]
 	if (value != null) this.push(value)
 }

 function parseSize(value, unit="") {
 	if (value == null) return null
 	let addon = "K"
 	let r_value = Math.round(value)
 	if (r_value >= 1000) {
 		addon = "M"
 		value /= 1000
 		r_value = Math.round(r_value / 1000)
 	}
 	if (r_value >= 1000) {
 		addon = "G"
 		value /= 1000
 		r_value = Math.round(r_value / 1000)
 	}
 	if (r_value >= 1000) {
 		addon = "T"
 		value /= 1000
 		r_value = Math.round(r_value / 1000)
 	}
 	let fixd = 0
 	let ferst = value.toFixed(2).split(".")[0].length
 	if (ferst == 1) fixd = 2
 	else if (ferst == 2) fixd = 1
 	value = value.toFixed(fixd)
 	if (!unit) unit = addon = ""
 	return `${value} ${addon}${unit}`
 }

 function mkTime(seconds) {
 	seconds = Math.round(seconds)
 	let m = Math.floor(seconds / 60) % 60
 	let h = Math.floor(seconds / 60 / 60) % 24
 	let d = Math.floor(seconds / 60 / 60 / 24)
 	let nice = ""
 	if (d) nice += `${d} day${s(d)} `
 	if (h) nice += `${h} hour${s(h)} `
 	if (m) nice += `${m} minute${s(m)} `
 	if (nice == "") nice = "Less than a minute"
 	return nice
 }

 function strToArray(str) {
 	if (Number.isInteger(str)) str = str.toString()
 	if (typeof(str) == "string") str = [str]
 	else if (!Array.isArray(str)) str = []
 	return str
 }

 function mkDiv(args, icon) {
 	let div = document.createElement((icon) ? "i" : "div")
 	if (args.id) div.id = args.id
 	if (args.className) div.className = args.className
 	if (args.text) {
 		if (args.raw_html) div.innerHTML = args.text
 		else div.innerText = args.text
 	}
 	return div;
 }

 function mkItem(target, icon, name, values, div_id) {
 	values = strToArray(values)
 	if (!values.length) return;
 	if (!div_id) div_id = icon
 	let id = `${target}-${div_id}`
 	let item = get(id)
 	let divs = (item) ? item.getElementsByClassName("value") : []
 	if (!item || divs.length != values.length) {
 		let _target = get(target)
 		let _item = mkDiv({className: "item", id})
 		let _icon = mkDiv({text: icon}, true)
 		let _text = mkDiv({className: "text"})
 		let _name = mkDiv({className: "name", text: name})
 		_text.appendChild(_name)
 		for (let _ of values) {
 			let val = mkDiv({className: "value"})
 			divs.append(val)
 			_text.appendChild(val)
 		}
 		_item.appendChild(_icon)
 		_item.appendChild(_text)
 		if (item) item.innerHTML = _item.innerHTML
 		else _target.appendChild(_item)
 	}
 	for (let i = 0; i < divs.length; i++) {
 		divs[i].innerText = values[i]
 	}
 }

 function mkBar(div, progress, value, unit, right, desc) {
 	let target = get(div)
 	if (!target.children.length) {
 		let _text = mkDiv({className: "text"})
 		let _value = mkDiv({className: "value"})
 		let _unit = mkDiv({className: "unit"})
 		let _right = mkDiv({className: "right"})
 		let _progress = mkDiv({className: "progress"})
 		let _desc = mkDiv({className: "desc"})
 		_text.appendChild(_value)
 		_text.appendChild(_unit)
 		_text.appendChild(_right)
 		target.appendChild(_text)
 		target.appendChild(_progress)
 		target.appendChild(_desc)
 	}
 	let _value = target.getElementsByClassName("value")[0]
 	let _unit = target.getElementsByClassName("unit")[0]
 	let _right = target.getElementsByClassName("right")[0]
 	let _desc = target.getElementsByClassName("desc")[0]
 	let _progress = target.getElementsByClassName("progress")[0]
 	_value.innerText = value
 	_unit.innerText = unit
 	_right.innerText = right
 	_desc.innerText = desc
 	_progress.style.setProperty("--value", `${progress * 100}%`)
 }

diff --git a/home/codermauro/Status/html/js/parser.js b/home/codermauro/Status/html/js/parser.js
index 0000000..0000000 100644
--- a/home/codermauro/Status/html/js/parser.js
+++ b/home/codermauro/Status/html/js/parser.js
@@ -1,182 +1,182 @@
 function updateDeviceName(deviceName) {
 	set("main-device-name", deviceName)
 }
 function updateCPU(cpu) {
 	// Temperatures
 	let temps = [],
 		temps_meltdown = []
 	for (let device in cpu.temperatures) {
 		let t = cpu.temperatures[device]
 		temps.append(t[0])
 		temps_meltdown.append(t[1])
 	}
 	let temp = temps.max()
 	let meltdown = temps_meltdown.min()

 	// Frequencies
 	let freq = [],
 		freq_base = [],
 		freq_min = [],
 		freq_max = []
 	for (let device in cpu.frequencies) {
 		let v = cpu.frequencies[device]
 		freq.append(v["now"])
 		freq_base.append(v["base"])
 		freq_min.append(v["min"])
 		freq_max.append(v["max"])
 	}
 	freq = freq.max()
 	freq_base = freq_base.max()
 	freq_min = freq_min.min()
 	freq_max = freq_max.max()

 	freq = (freq) ? parseSize(freq * 1000, "Hz") : ""


 	// Add to UI
 	let _values_cpu = []
 	_values_cpu.addNode(`${Math.round(cpu.utilisation * 100)}%`)
 	_values_cpu.addNode(freq, freq != "")
 	_values_cpu.addNode(`${temp} °C`, temp)
 	set("main-cpu", _values_cpu.join(", "))

 	mkBar("cpu-bar",
 		cpu.utilisation, Math.round(cpu.utilisation * 100), "%",
 		(freq) ? `Speed: ${freq}` : "",
 		cpu.model
 	)

 	let _values_temp = []
 	_values_temp.addNode(`Current: ${Math.round(temp* 10) / 10} °C`, temp)
 	_values_temp.addNode(`Meltdown: ${Math.round(meltdown* 10) / 10} °C`, meltdown)
 	mkItem("cpu-list", "thermostat", "Temperature", _values_temp)

 	mkItem("cpu-list", "numbers", "Core count", [
 		`${cpu.cores} core${s(cpu.cores)}, ${cpu.count} thread${s(cpu.count)}`
 	])

 	let _values_freq = []
 	_values_freq.addNode(`${parseSize(freq_min * 1000, "Hz")} up to ${parseSize(freq_max * 1000, "Hz")}`, (freq_min && freq_max))
 	_values_freq.addNode(`Base: ${parseSize(freq_base * 1000, "Hz")}`, freq_base)
 	mkItem("cpu-list", "speed", "Speed", _values_freq)

 	mkItem("cpu-list", "cached", "Cache size", parseSize(cpu.cache / 1024 * 1000, "B"))
 }


 function updateMem(mem) {
 	// Parse data
 	let swap_used = mem.swap_total - mem.swap_available
 	let mem_used = mem.total - mem.available
 	let m = parseSize(mem_used, "B").split(" ")


 	// Add to UI
 	set("main-mem", `Using ${m.join(" ")} out of ${parseSize(mem.total, "B")}`)

 	mkBar("mem-bar",
 		mem_used / mem.total, m[0], m[1],
 		`${parseSize(mem.total, "B")} in total`,
 		`${parseSize(mem.available, "B")} is available`
 	)

 	let _values_swap = []
 	_values_swap.addNode(`Using ${parseSize(swap_used, "B")} out of ${parseSize(mem.swap_total, "B")}`, mem.swap_total != 0)
 	_values_swap.addNode(`${parseSize(mem.swap_available, "B")} is available`, mem.swap_total != 0)
 	_values_swap.addNode(`Unavailable`, mem.swap_total == 0)
 	mkItem("mem-list", "extension", "Swap", _values_swap)

 	mkItem("mem-list", "cached", "Cached", parseSize(mem.cached, "B"))
 	mkItem("mem-list", "account_tree", "Processes", mem.processes)
 }

 var storage_last = []
 function updateStorage(storage) {
 	let all_total = 0
 	let all_used  = 0
 	for (let disk in storage) {
 		let p = storage[disk]
 		let used = p.total - p.available

 		// Add to disks list
 		mkItem("storage-list", p.icon, disk, [
 			`Using ${parseSize(used / 1000, "B")} out of ${parseSize(p.total / 1000, "B")}`,
 			`${parseSize(p.available / 1000, "B")} is available`
 		], disk)

 		all_used += used
 		all_total += p.total
 	}

 	// Clean unused disks
 	if (Object.keys(storage_last).length > 0) {
 		for (let last_disk in storage_last) {
 			if (!(last_disk in storage)) {
 				document.getElementById(`storage-list-${last_disk}`).remove()
 			}
 		}
 	}

 	let all_free = all_total - all_used
 	let s = parseSize(all_used / 1000, "B").split(" ")


 	// Add to UI
 	set("main-storage", `Using ${s.join(" ")} out of ${parseSize(all_total / 1000, "B")}`)

 	mkBar("storage-bar",
 		all_used / all_total, s[0], s[1],
 		`${parseSize(all_total / 1000, "B")} in total`,
 		`${parseSize(all_free / 1000, "B")} is available`
 	)

 	storage_last = storage
 }


 function updateNet(net_last, net) {
 	let rx_diff = net.rx - net_last.rx
 	let tx_diff = net.tx - net_last.tx
 	let rx_speed = rx_diff / 1.5 / (1000 / 8)
 	let tx_speed = tx_diff / 1.5 / (1000 / 8)

 	set("main-network", parseSize(rx_speed + tx_speed, "bit/s"))

 	set("net-up-speed", parseSize(tx_speed, "bit/s"))
 	set("net-up-speed-bytes", parseSize(tx_speed / 8, "B/s"))
 	set("net-down-speed", parseSize(rx_speed, "bit/s"))
 	set("net-down-speed-bytes", parseSize(rx_speed / 8, "B/s"))

 	let netspeed

 	if (typeof net.speed === "string" && net.speed.includes(";")) {
 		let parts = net.speed.split(";")
 		if (parts.length === 3) {
 			netspeed = `Ping: ${parts[0]} ms, Down: ${parts[1]} mbps, Up: ${parts[2]} mbps`
 		} else {
 			netspeed = "Invalid format"
 		}
 	} else {
 		netspeed = (net.speed !== -1) ? parseSize(net.speed * 1000, "bit/s") : "Unknown"
 	}

 	mkItem("net-list", "speed", "Connection speed", netspeed)

 	mkItem("net-list", "arrow_upward", "Upload", [
 		`${parseSize(net.tx / 1000, "B")} since boot`
 	])
 	mkItem("net-list", "arrow_downward", "Download", [
 		`${parseSize(net.rx / 1000, "B")} since boot`
 	])
 }


 function updateHost(host) {
 	set("main-host", host.os)
 	mkItem("host-list", "text_format", "Device name", host.hostname)
 	mkItem("host-list", "settings", "Operating system", host.os)
 	mkItem("host-list", "timer", "Uptime", mkTime(host.uptime))
 	mkItem("host-list", "memory", "App memory", parseSize(host.app_memory, "B"))
 	mkItem("host-list", "speed", "Load averages", host.loadavg.join(", "))
 }

