   -webkit-tap-highlight-color: transparent;
   transition: opacity .5s, background .4s, color .4s;
 }
 .screen { min-height: 100vh; }
 .wrapper {
   width: calc(100% - 24px);
   max-width: 980px;
   margin: 0 auto;
   padding-bottom: 40px;
 }
 .hero {
   text-align: center;
   padding: 68px 8px 24px;
 }
 .hero h1 {
   margin: 0;
   font-size: 64px;
   letter-spacing: -1px;
 }
 .hero p {
   margin: 6px 0 0;
   opacity: 0.66;
 }
 .panel {
   background: hsl(var(--color), 13%, 6%);
   border-radius: 26px;
   padding: 14px;
   margin: 10px 4px;
   box-shadow: inset 0 0 0 1px hsl(var(--color), 12%, 10%);
 }
 .panel-header {
   display: flex;
   align-items: center;
   margin: 0 4px 12px;
 }
 .panel-header h2 {
   font-size: 24px;
   margin: 0;
 }
 .panel-header button {
   margin-left: auto;
 }
 .path-pill {
   margin: 0 4px 10px;
   padding: 10px 12px;
   border-radius: 14px;
   font-size: 12px;
   opacity: 0.75;
   background: hsl(var(--color), 14%, 9%);
   white-space: nowrap;
   overflow: hidden;
   text-overflow: ellipsis;
 }
 .action-row {
   display: flex;
   flex-wrap: wrap;
   gap: 8px;
   margin: 0 4px 10px;
 }
 button, input[type="text"], .toggle {
   border: none;
   border-radius: 14px;
   background: hsl(var(--color), 15%, 10%);
   color: inherit;
   font-family: inherit;
   font-weight: 700;
 }
 button {
   padding: 10px 14px;
   cursor: pointer;
 }
 button:hover { background: hsl(var(--color), 14%, 14%); }
 button.ghost { background: hsl(var(--color), 14%, 8%); }
 button.ghost:hover { background: hsl(var(--color), 14%, 12%); }
 input[type="text"] {
   outline: none;
   padding: 10px 12px;
   min-width: 200px;
 }
 .toggle {
   display: inline-flex;
   align-items: center;
   gap: 6px;
   padding: 8px 10px;
   font-size: 12px;
 }
 .list { padding: 2px; }
 .item {
   margin: 8px 2px;
   padding: 14px;
   border-radius: 18px;
   background: hsl(var(--color), 14%, 8%);
   display: flex;
   align-items: flex-start;
   gap: 12px;
 }
 .item .name { font-size: 16px; }
