1. const state = {
2.   baseDir: "",
3.   currentPath: "",
4.   parentPath: null,
5.   openLogSessionId: null,
6.   openLogContent: "",
7. };
8. 
9. const els = {
10.   dirList: document.getElementById("dir-list"),
11.   sessionList: document.getElementById("session-list"),
12.   pathLabel: document.getElementById("path-label"),
13.   upBtn: document.getElementById("up-btn"),
14.   deployHereBtn: document.getElementById("deploy-here-btn"),
15.   deployHereYolo: document.getElementById("deploy-here-yolo"),
16.   initRepoBtn: document.getElementById("init-repo-btn"),
17.   createFolderBtn: document.getElementById("create-folder-btn"),
18.   newFolderName: document.getElementById("new-folder-name"),
19.   cloneRepoUrl: document.getElementById("clone-repo-url"),
20.   cloneFolderName: document.getElementById("clone-folder-name"),
21.   cloneRepoBtn: document.getElementById("clone-repo-btn"),
22.   flash: document.getElementById("flash"),
23.   refreshBtn: document.getElementById("refresh-btn"),
24.   accents: document.querySelector(".accents"),
25.   themeLight: document.getElementById("theme-light"),
26.   themeDark: document.getElementById("theme-dark"),
27. };
28. 
29. async function request(url, options = {}) {
30.   const res = await fetch(url, options);
31.   const data = await res.json();
32.   if (!res.ok) throw new Error(data.error || "Request failed.");
33.   return data;
34. }
35. 
36. function escapeHtml(text) {
37.   return String(text)
38.     .replaceAll("&", "&amp;")
39.     .replaceAll("<", "&lt;")
40.     .replaceAll(">", "&gt;")
41.     .replaceAll('"', "&quot;")
42.     .replaceAll("'", "&#39;");
43. }
44. 
45. function setFlash(message, type = "ok") {
46.   if (!els.flash) {
47.     console.warn("[ui] flash element missing:", message);
48.     return;
49.   }
50.   els.flash.classList.remove("ok", "error");
51.   els.flash.classList.add(type);
52.   els.flash.textContent = message;
53. }
54. 
55. function selectAccent(accent, save = true) {
56.   if (!els.accents) return;
57.   const cleanAccent = String(accent || "").replace("selected", "").trim();
58.   const available = Array.from(els.accents.children);
59.   for (const color of available) {
60.     const colorName = color.className.replace("selected", "").trim();
61.     if (colorName === cleanAccent) {
62.       color.classList.add("selected");
63.       document.body.classList.add(cleanAccent);
64.     } else {
65.       color.classList.remove("selected");
66.       if (colorName) document.body.classList.remove(colorName);
67.     }
68.   }
69.   if (!save) return;
70.   localStorage.setItem("statusapp-accent", cleanAccent);
71. }
72. 
73. function selectTheme(isLight, save = true) {
74.   if (isLight) document.body.classList.add("light");
75.   else document.body.classList.remove("light");
76.   els.themeLight?.classList.toggle("selected", isLight);
77.   els.themeDark?.classList.toggle("selected", !isLight);
78.   if (!save) return;
79.   localStorage.setItem("statusapp-light", String(Boolean(isLight)));
80. }
81. 
82. function loadThemePicker() {
83.   if (!els.accents) return;
84.   for (const accent of els.accents.children) {
85.     accent.addEventListener("click", () => {
86.       selectAccent(accent.className);
87.     });
88.   }
89.   els.themeLight?.addEventListener("click", () => selectTheme(true));
90.   els.themeDark?.addEventListener("click", () => selectTheme(false));
91. }
92. 
93. async function loadConfig() {
94.   const data = await request("/api/config");
95.   state.baseDir = data.baseDir;
96. }
97. 
98. async function loadDirectory(path) {
99.   const url = new URL("/api/tree", window.location.origin);
100.   if (path) url.searchParams.set("path", path);
101.   const data = await request(url.toString());
102.   state.currentPath = data.currentPath;
103.   state.parentPath = data.parentPath;
104.   els.pathLabel.textContent = data.currentPath;
105.   els.upBtn.disabled = !data.parentPath;
106. 
107.   els.dirList.innerHTML = data.children.length
108.     ? data.children.map((dir) => {
109.         const escapedPath = escapeHtml(dir.path);
110.         const escapedName = escapeHtml(dir.name);
111.         const escapedRel = escapeHtml(dir.relativePath);
112.         return `
113.           <div class="item">
114.             <div>
115.               <div class="name">${escapedName}</div>
116.               <div class="meta">${escapedRel}</div>
117.             </div>
118.             <div class="right">
119.               <button data-open="${escapedPath}">Open</button>
120.               <div class="inline-actions">
121.                 <button data-launch="${escapedPath}">Deploy</button>
122.                 <label class="toggle">
123.                   <input type="checkbox" data-item-yolo>
124.                   <span>--yolo</span>
125.                 </label>
126.               </div>
127.             </div>
128.           </div>
129.         `;
130.       }).join("")
131.     : `<div class="item"><div><div class="name">This folder is empty</div><div class="meta">Use Deploy Here, Create Folder, Clone Repo, or Init Git Here.</div></div></div>`;
132. }
133. 
134. function renderSessionLog(sessionId) {
135.   if (state.openLogSessionId !== sessionId) return "";
136.   return `<pre class="session-log">${escapeHtml(state.openLogContent || "(no output yet)")}</pre>`;
137. }
138. 
139. async function loadSessions() {
140.   const data = await request("/api/sessions");
141.   els.sessionList.innerHTML = data.sessions.length
142.     ? data.sessions.map((session) => {
143.         const escapedId = escapeHtml(session.id);
144.         const escapedDir = escapeHtml(session.directory);
145.         const escapedArgs = escapeHtml(session.args.join(" "));
146.         const outputButton = state.openLogSessionId === session.id ? "Hide Output" : "Show Output";
147.         return `
148.           <div class="item">
149.             <div style="flex:1;">
150.               <div class="name">${escapedDir}</div>
151.               <div class="meta">PID ${session.pid} · ${session.command} ${escapedArgs}</div>
152.               <div class="badge status-${session.status}">${escapeHtml(session.status)}</div>
153.               ${renderSessionLog(session.id)}
154.             </div>
155.             <div class="right">
156.               <button data-output="${escapedId}">${outputButton}</button>
157.               <button data-stop="${escapedId}">Stop</button>
158.               <button data-remove="${escapedId}">Remove</button>
159.             </div>
160.           </div>
161.         `;
162.       }).join("")
163.     : `<div class="item"><div class="meta">No sessions yet.</div></div>`;
164. }
165. 
166. async function createSession(dirPath, yolo) {
167.   await request("/api/sessions", {
168.     method: "POST",
169.     headers: { "Content-Type": "application/json" },
170.     body: JSON.stringify({ path: dirPath, yolo: Boolean(yolo) }),
171.   });
172.   await loadSessions();
173.   setFlash(`Session launched in ${dirPath}`, "ok");
174. }
175. 
176. async function stopSession(id) {
177.   await request(`/api/sessions/${encodeURIComponent(id)}/stop`, { method: "POST" });
178.   await loadSessions();
179. }
180. 
181. async function removeSession(id) {
182.   await request(`/api/sessions/${encodeURIComponent(id)}`, { method: "DELETE" });
183.   if (state.openLogSessionId === id) {
184.     state.openLogSessionId = null;
185.     state.openLogContent = "";
186.   }
187.   await loadSessions();
188. }
189. 
190. async function createFolder() {
191.   const folderName = els.newFolderName.value.trim();
192.   if (!folderName) throw new Error("Folder name is required.");
193.   await request("/api/folders", {
194.     method: "POST",
195.     headers: { "Content-Type": "application/json" },
196.     body: JSON.stringify({ parentPath: state.currentPath, name: folderName }),
197.   });
198.   els.newFolderName.value = "";
199.   await loadDirectory(state.currentPath);
200.   setFlash(`Created folder: ${folderName}`, "ok");
201. }
202. 
203. async function cloneRepo() {
204.   const repoUrl = els.cloneRepoUrl.value.trim();
205.   const folderName = els.cloneFolderName.value.trim();
206.   if (!repoUrl) throw new Error("Repository URL is required.");
207.   await request("/api/clone", {
208.     method: "POST",
209.     headers: { "Content-Type": "application/json" },
210.     body: JSON.stringify({
211.       parentPath: state.currentPath,
212.       repoUrl,
213.       folderName: folderName || undefined,
214.     }),
215.   });
216.   els.cloneFolderName.value = "";
217.   await loadDirectory(state.currentPath);
218.   setFlash("Repository cloned.", "ok");
219. }
220. 
221. async function initRepoHere() {
222.   await request("/api/init-repo", {
223.     method: "POST",
224.     headers: { "Content-Type": "application/json" },
225.     body: JSON.stringify({ path: state.currentPath }),
226.   });
227.   setFlash("Initialized git repository.", "ok");
228. }
229. 
230. async function toggleOutput(id) {
231.   if (state.openLogSessionId === id) {
232.     state.openLogSessionId = null;
233.     state.openLogContent = "";
234.     await loadSessions();
235.     return;
236.   }
237.   const data = await request(`/api/sessions/${encodeURIComponent(id)}/log?tail=400`);
238.   state.openLogSessionId = id;
239.   state.openLogContent = data.output || "";
240.   await loadSessions();
241. }
242. 
243. function bindEvents() {
244.   if (
245.     !els.upBtn || !els.refreshBtn || !els.initRepoBtn || !els.deployHereBtn
246.     || !els.createFolderBtn || !els.cloneRepoBtn || !els.dirList || !els.sessionList
247.   ) {
248.     throw new Error("UI failed to initialize: required elements are missing.");
249.   }
250. 
251.   els.upBtn.addEventListener("click", async () => {
252.     if (!state.parentPath) return;
253.     await loadDirectory(state.parentPath);
254.   });
255. 
256.   els.refreshBtn.addEventListener("click", loadSessions);
257. 
258.   els.initRepoBtn.addEventListener("click", async () => {
259.     try {
260.       await initRepoHere();
261.     } catch (error) {
262.       setFlash(error.message, "error");
263.     }
264.   });
265. 
266.   els.deployHereBtn.addEventListener("click", async () => {
267.     try {
268.       await createSession(state.currentPath, els.deployHereYolo.checked);
269.     } catch (error) {
270.       setFlash(error.message, "error");
271.     }
272.   });
273. 
274.   els.createFolderBtn.addEventListener("click", async () => {
275.     try {
276.       await createFolder();
277.     } catch (error) {
278.       setFlash(error.message, "error");
279.     }
280.   });
281. 
282.   els.cloneRepoBtn.addEventListener("click", async () => {
283.     try {
284.       await cloneRepo();
285.     } catch (error) {
286.       setFlash(error.message, "error");
287.     }
288.   });
289. 
290.   els.dirList.addEventListener("click", async (event) => {
291.     const openBtn = event.target.closest("button[data-open]");
292.     if (openBtn) {
293.       await loadDirectory(openBtn.dataset.open);
294.       return;
295.     }
296. 
297.     const launchBtn = event.target.closest("button[data-launch]");
298.     if (launchBtn) {
299.       try {
300.         const item = launchBtn.closest(".item");
301.         const yoloChecked = Boolean(item && item.querySelector("input[data-item-yolo]")?.checked);
302.         await createSession(launchBtn.dataset.launch, yoloChecked);
303.       } catch (error) {
304.         setFlash(error.message, "error");
305.       }
306.     }
307.   });
308. 
309.   els.sessionList.addEventListener("click", async (event) => {
310.     const outputBtn = event.target.closest("button[data-output]");
311.     if (outputBtn) {
312.       try {
